const TARIFS_DISTANCE = [
  {km:10,prix:250},{km:20,prix:250},{km:30,prix:250},{km:40,prix:320},
  {km:50,prix:350},{km:60,prix:390},{km:70,prix:430},{km:80,prix:500},
  {km:90,prix:540},{km:100,prix:580},{km:110,prix:620},{km:120,prix:660},
  {km:130,prix:700},{km:140,prix:740},{km:150,prix:780},{km:160,prix:820},
  {km:170,prix:860},{km:180,prix:900},
];
const COEF_SAISON = {
  basse:      {taux:-0.07, mois:[11,1,2,8]},
  moyenne:    {taux: 0.00, mois:[12,10,9]},
  haute:      {taux: 0.10, mois:[3,4,7]},
  tres_haute: {taux: 0.15, mois:[5,6]},
};
const COEF_ANTICIPATION = [
  {code:'DD_PRIORITAIRE', taux: 0.10, min:0,  max:14},
  {code:'DD_URGENT',      taux: 0.05, min:15, max:30},
  {code:'DD_NORMAL',      taux:-0.05, min:31, max:90},
  {code:'DD_3MOISETPLUS', taux:-0.10, min:91, max:Infinity},
];
const COEF_CAPACITE = [
  {code:'cap_0_19',  taux:-0.05, min:0,  max:19},
  {code:'cap_20_53', taux: 0.00, min:20, max:53},
  {code:'cap_54_63', taux: 0.15, min:54, max:63},
  {code:'cap_64_67', taux: 0.20, min:64, max:67},
  {code:'cap_68_85', taux: 0.40, min:68, max:85},
];
const OPTIONS = { guide:80, nuit_chauffeur:120, peages:0 };
const TVA = 0.10, MARGE = 0.15, SEUIL_ESCALADE_PAX = 85, TARIF_KM_AU_DELA_180 = 2.5;

const r2 = x => Math.round(x*100)/100;

function baseTransfertSimple(km){
  if (km <= 180){
    const p = TARIFS_DISTANCE.find(t => km <= t.km);
    return p ? p.prix : TARIFS_DISTANCE[TARIFS_DISTANCE.length-1].prix;
  }
  return (km * 2) * TARIF_KM_AU_DELA_180;
}
function coefSaison(date){
  const m = date.getMonth()+1;
  for (const [code,info] of Object.entries(COEF_SAISON))
    if (info.mois.includes(m)) return {type:'saison', code, taux:info.taux};
  return {type:'saison', code:'moyenne', taux:0};
}
function coefAnticipation(j){
  const row = COEF_ANTICIPATION.find(r => j>=r.min && j<=r.max);
  return {type:'anticipation', code: row?row.code:'?', taux: row?row.taux:0};
}
function coefCapacite(n){
  const row = COEF_CAPACITE.find(r => n>=r.min && n<=r.max);
  return {type:'capacite', code: row?row.code:'?', taux: row?row.taux:0};
}
function normalize(d){
  const depart = d.date_depart ? new Date(d.date_depart) : null;
  const retour = d.date_retour ? new Date(d.date_retour) : null;
  let nbJours = d.nb_jours, nbNuits = d.nb_nuits;
  if (nbJours == null)
    nbJours = (depart && retour && !isNaN(depart) && !isNaN(retour))
      ? Math.max(1, Math.round((retour-depart)/86400000)+1) : 1;
  if (nbNuits == null) nbNuits = Math.max(0, nbJours-1);
  return {...d, _depart:depart, nbJours, nbNuits};
}

function calculerDevis(input){
  const d = normalize(input);
  const lignes = [], coefficients = [];

  // --- garde-fous ---
  if (!d.nb_passagers || d.nb_passagers <= 0)
    return {statut:'erreur', escalade:false, motif:'Nombre de passagers invalide'};
  if (d.nb_passagers > SEUIL_ESCALADE_PAX)
    return {statut:'escalade', escalade:true, motif:`> ${SEUIL_ESCALADE_PAX} passagers : flux manuel (validation humaine)`};
  if (!d.distance_km || d.distance_km <= 0)
    return {statut:'erreur', escalade:false, motif:'Distance invalide'};
  if (!d._depart || isNaN(d._depart))
    return {statut:'erreur', escalade:false, motif:'Date de départ invalide'};
  const dDemande = d.date_demande ? new Date(d.date_demande) : new Date();
  const joursAvant = Math.ceil((d._depart - dDemande)/86400000);
  if (joursAvant < 0)
    return {statut:'erreur', escalade:false, motif:'Date de départ antérieure à la demande'};

  // --- 1) base distance ---
  let base = baseTransfertSimple(d.distance_km);
  lignes.push({libelle:`Base distance (${d.distance_km} km, transfert simple)`, montant:r2(base)});
  if (d.aller_retour){ lignes.push({libelle:'Aller/retour (x2)', montant:r2(base)}); base *= 2; }

  // --- 2) coefficients sur la base transport ---
  const cS = coefSaison(d._depart), cA = coefAnticipation(joursAvant), cC = coefCapacite(d.nb_passagers);
  coefficients.push(cS, cA, cC);
  for (const c of [cS, cA, cC])
    lignes.push({libelle:`Coefficient ${c.type} (${c.code}, ${(c.taux*100).toFixed(0)}%)`, montant:r2(base*c.taux)});
  const sommeCoef = cS.taux + cA.taux + cC.taux;
  const montantTransport = base * (1 + sommeCoef);

  // --- 3) options ---
  let totalOptions = 0;
  const opts = d.options || [];
  if (opts.includes('guide')){ const m=OPTIONS.guide*d.nbJours; totalOptions+=m; lignes.push({libelle:`Option guide (${d.nbJours} j x ${OPTIONS.guide}€)`, montant:r2(m)}); }
  if (opts.includes('nuit_chauffeur')){ const m=OPTIONS.nuit_chauffeur*d.nbNuits; totalOptions+=m; lignes.push({libelle:`Option nuit chauffeur (${d.nbNuits} nuit(s) x ${OPTIONS.nuit_chauffeur}€)`, montant:r2(m)}); }
  if (opts.includes('peages')) lignes.push({libelle:'Option péages (forfait à préciser)', montant:0});

  // --- 4) marge puis 5) TVA ---
  const sousTotal = montantTransport + totalOptions;
  const marge = sousTotal * MARGE;
  lignes.push({libelle:`Marge commerciale (+${(MARGE*100).toFixed(0)}%)`, montant:r2(marge)});
  const prixHT = sousTotal + marge;
  const tva = prixHT * TVA;
  const prixTTC = prixHT + tva;

  return {
    statut:'ok', escalade:false, devise:'EUR',
    prix_ht:r2(prixHT), tva:r2(tva), prix_ttc:r2(prixTTC),
    lignes, coefficients,
    meta:{ jours_avant_depart:joursAvant, nb_jours:d.nbJours, nb_nuits:d.nbNuits, somme_coefficients:sommeCoef },
  };
}

