let output = $json.output || "";

output = output
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

try {
  const parsed = JSON.parse(output);

  return [{
    json: {
      reply: parsed.reply,
      data_devis: parsed.data_devis
    }
  }];
} catch (error) {
  return [{
    json: {
      reply: output,
      data_devis: null,
      parse_error: error.message
    }
  }];
}

